306	pub fn which(globalThis: *jsc.JSGlobalObject, callframe: *jsc.CallFrame) bun.JSError!jsc.JSValue {
307	    const arguments_ = callframe.arguments_old(2);
308	    const path_buf = bun.path_buffer_pool.get();
309	    defer bun.path_buffer_pool.put(path_buf);
310	    var arguments = jsc.CallFrame.ArgumentsSlice.init(globalThis.bunVM(), arguments_.slice());
311	    defer arguments.deinit();
312	    const path_arg = arguments.nextEat() orelse {
313	        return globalThis.throw("which: expected 1 argument, got 0", .{});
314	    };
315	
316	    var path_str: ZigString.Slice = ZigString.Slice.empty;
317	    var bin_str: ZigString.Slice = ZigString.Slice.empty;
318	    var cwd_str: ZigString.Slice = ZigString.Slice.empty;
319	    defer {
320	        path_str.deinit();
321	        bin_str.deinit();
322	        cwd_str.deinit();
323	    }
324	
325	    if (path_arg.isEmptyOrUndefinedOrNull()) {
326	        return jsc.JSValue.jsNull();
327	    }
328	
329	    bin_str = try path_arg.toSlice(globalThis, globalThis.bunVM().allocator);
330	    if (globalThis.hasException()) {
331	        return .zero;
332	    }
333	
334	    if (bin_str.len >= bun.MAX_PATH_BYTES) {
335	        return globalThis.throw("bin path is too long", .{});
336	    }
337	
338	    if (bin_str.len == 0) {
339	        return jsc.JSValue.jsNull();
340	    }
341	
342	    path_str = ZigString.Slice.fromUTF8NeverFree(
343	        globalThis.bunVM().transpiler.env.get("PATH") orelse "",
344	    );
345	    cwd_str = ZigString.Slice.fromUTF8NeverFree(
346	        globalThis.bunVM().transpiler.fs.top_level_dir,
347	    );
348	
349	    if (arguments.nextEat()) |arg| {
350	        if (!arg.isEmptyOrUndefinedOrNull() and arg.isObject()) {
351	            if (try arg.get(globalThis, "PATH")) |str_| {
352	                path_str = try str_.toSlice(globalThis, globalThis.bunVM().allocator);
353	            }
354	
355	            if (try arg.get(globalThis, "cwd")) |str_| {
356	                cwd_str = try str_.toSlice(globalThis, globalThis.bunVM().allocator);
357	            }
358	        }
359	    }
360	
361	    if (Which.which(
362	        path_buf,
363	        path_str.slice(),
364	        cwd_str.slice(),
365	        bin_str.slice(),
366	    )) |bin_path| {
367	        return ZigString.init(bin_path).withEncoding().toJS(globalThis);
368	    }
369	
370	    return jsc.JSValue.jsNull();
371	}
