373	pub fn inspectTable(globalThis: *jsc.JSGlobalObject, callframe: *jsc.CallFrame) bun.JSError!jsc.JSValue {
374	    var args_buf = callframe.argumentsUndef(5);
375	    var all_arguments = args_buf.mut();
376	    if (all_arguments[0].isUndefinedOrNull() or !all_arguments[0].isObject())
377	        return bun.String.empty.toJS(globalThis);
378	
379	    for (all_arguments) |arg| {
380	        arg.protect();
381	    }
382	    defer {
383	        for (all_arguments) |arg| {
384	            arg.unprotect();
385	        }
386	    }
387	
388	    var arguments = all_arguments[0..];
389	    const value = arguments[0];
390	
391	    if (!arguments[1].isArray()) {
392	        arguments[2] = arguments[1];
393	        arguments[1] = .js_undefined;
394	    }
395	
396	    var formatOptions = ConsoleObject.FormatOptions{
397	        .enable_colors = false,
398	        .add_newline = false,
399	        .flush = false,
400	        .max_depth = 5,
401	        .quote_strings = true,
402	        .ordered_properties = false,
403	        .single_line = true,
404	    };
405	    if (arguments[2].isObject()) {
406	        try formatOptions.fromJS(globalThis, arguments[2..]);
407	    }
408	
409	    // very stable memory address
410	    var array = std.Io.Writer.Allocating.init(bun.default_allocator);
411	    defer array.deinit();
412	    const writer = &array.writer;
413	
414	    const Writer = @TypeOf(writer);
415	    const properties: JSValue = if (arguments[1].jsType().isArray()) arguments[1] else .js_undefined;
416	    var table_printer = try ConsoleObject.TablePrinter.init(
417	        globalThis,
418	        .Log,
419	        value,
420	        properties,
421	    );
422	    table_printer.value_formatter.depth = formatOptions.max_depth;
423	    table_printer.value_formatter.ordered_properties = formatOptions.ordered_properties;
424	    table_printer.value_formatter.single_line = formatOptions.single_line;
425	
426	    switch (formatOptions.enable_colors) {
427	        inline else => |colors| table_printer.printTable(Writer, writer, colors) catch {
428	            if (!globalThis.hasException())
429	                return globalThis.throwOutOfMemory();
430	            return .zero;
431	        },
432	    }
433	
434	    writer.flush() catch |e| switch (e) {
435	        error.WriteFailed => return error.OutOfMemory,
436	    };
437	
438	    return bun.String.createUTF8ForJS(globalThis, array.written());
439	}
