29	    inline fn shouldSkipLine(line: []const u8) bool {
30	        if (line.len == 0 or
31	            // comments
32	            line[0] == ';' or
33	            line[0] == '#') return true;
34	
35	        // check the rest is whitespace
36	        for (line) |c| {
37	            switch (c) {
38	                ' ', '\t', '\n', '\r' => {},
39	                '#', ';' => return true,
40	                else => return false,
41	            }
42	        }
43	        return true;
