203	    fn prepareStr(
204	        this: *Parser,
205	        arena_allocator: Allocator,
206	        ropealloc: Allocator,
207	        val_: []const u8,
208	        offset_: i32,
209	        comptime usage: enum { section, key, value },
210	    ) OOM!switch (usage) {
211	        .value => Expr,
212	        .section => *Rope,
