238	            if (json_val.asString(arena_allocator)) |str| {
239	                // Expand env vars in the JSON-parsed string
240	                const expanded = if (comptime usage == .value) try this.expandEnvVars(arena_allocator, str) else str;
241	                if (comptime usage == .value) return Expr.init(E.String, E.String.init(expanded), Loc{ .start = @intCast(offset) });
