248	            // unfortunately, we need to match npm/ini behavior here,
249	            // which requires us to turn these into a string,
250	            // same behavior as doing this:
251	            // ```
252	            // let foo = {}
253	            // const json_val = { hi: 'hello' }
254	            // foo[json_val] = 'nice'
255	            // ```
256	            switch (json_val.data) {
257	                .e_object => {
258	                    if (comptime usage == .section) return singleStrRope(ropealloc, "[Object object]");
