348	                            try unesc.append('.');
349	                        }
350	                    },
351	                    else => switch (bun.strings.utf8ByteSequenceLength(c)) {
352	                        0, 1 => try unesc.append(c),
353	                        2 => if (val.len - i >= 2) {
354	                            try unesc.appendSlice(&[_]u8{ c, val[i + 1] });
355	                            i += 1;
356	                        } else {
357	                            try unesc.append(c);
358	                        },
359	                        3 => if (val.len - i >= 3) {
360	                            try unesc.appendSlice(&[_]u8{ c, val[i + 1], val[i + 2] });
361	                            i += 2;
362	                        } else {
363	                            try unesc.appendSlice(val[i..val.len]);
364	                            i = val.len - 1;
365	                        },
366	                        4 => if (val.len - i >= 4) {
367	                            try unesc.appendSlice(&[_]u8{ c, val[i + 1], val[i + 2], val[i + 3] });
368	                            i += 3;
369	                        } else {
370	                            try unesc.appendSlice(val[i..val.len]);
371	                            i = val.len - 1;
372	                        },
373	                        else => unreachable,
374	                    },
375	                }
376	            }
377	
378	            if (esc)
379	                try unesc.append('\\');
380	
381	            switch (usage) {
382	                .section => {
383	                    try this.commitRopePart(arena_allocator, ropealloc, &unesc, &rope);
384	                    return rope.?;
385	                },
386	                .value => {
387	                    if (!did_any_escape) return Expr.init(E.String, E.String.init(val[0..]), Loc{ .start = offset });
388	                    if (unesc.items.len <= STACK_BUF_SIZE) return Expr.init(
389	                        E.String,
390	                        E.String.init(try arena_allocator.dupe(u8, unesc.items[0..])),
391	                        Loc{ .start = offset },
392	                    );
393	                    return Expr.init(E.String, E.String.init(unesc.items[0..]), Loc{ .start = offset });
394	                },
395	                .key => {
396	                    const thestr: []const u8 = thestr: {
397	                        if (!did_any_escape) break :thestr try arena_allocator.dupe(u8, val[0..]);
398	                        if (unesc.items.len <= STACK_BUF_SIZE) break :thestr try arena_allocator.dupe(u8, unesc.items[0..]);
399	                        break :thestr unesc.items[0..];
400	                    };
401	                    return thestr;
402	                },
403	            }
404	        }
405	        if (comptime usage == .value) return Expr.init(E.String, E.String.init(val[0..]), Loc{ .start = offset });
406	        if (comptime usage == .key) return val[0..];
407	        return strToRope(ropealloc, val[0..]);
408	    }
