410	    /// Expands ${VAR} and ${VAR?} environment variable substitutions in a string.
411	    /// Used for quoted values after JSON parsing has already handled escape sequences.
412	    ///
413	    /// Behavior (same as unquoted):
414	    /// - ${VAR} - if VAR is undefined, leave as "${VAR}" (no expansion)
415	    /// - ${VAR?} - if VAR is undefined, expand to empty string
416	    /// - Backslash escaping is already handled by JSON parsing
417	    fn expandEnvVars(this: *Parser, allocator: Allocator, val: []const u8) OOM![]const u8 {
418	        // Quick check if there are any env vars to expand
419	        if (std.mem.indexOf(u8, val, "${") == null) {
420	            return val;
421	        }
422	
423	        var result = try std.array_list.Managed(u8).initCapacity(allocator, val.len);
424	        var i: usize = 0;
425	        while (i < val.len) {
426	            if (val[i] == '$' and i + 2 < val.len and val[i + 1] == '{') {
427	                // Find the closing brace
428	                var j = i + 2;
429	                var depth: usize = 1;
430	                while (j < val.len and depth > 0) {
431	                    if (val[j] == '{') {
432	                        depth += 1;
433	                    } else if (val[j] == '}') {
434	                        depth -= 1;
435	                    }
436	                    if (depth > 0) j += 1;
437	                }
438	                if (depth == 0) {
439	                    const env_var_raw = val[i + 2 .. j];
440	                    const optional = env_var_raw.len > 0 and env_var_raw[env_var_raw.len - 1] == '?';
441	                    const env_var = if (optional) env_var_raw[0 .. env_var_raw.len - 1] else env_var_raw;
442	
443	                    if (this.env.get(env_var)) |expanded| {
444	                        try result.appendSlice(expanded);
445	                    } else if (!optional) {
446	                        // Not found and not optional: leave as-is
447	                        try result.appendSlice(val[i .. j + 1]);
448	                    }
449	                    // If optional and not found: expand to empty string (append nothing)
450	                    i = j + 1;
451	                    continue;
452	                }
453	            }
454	            try result.append(val[i]);
455	            i += 1;
456	        }
457	        return result.items;
458	    }
