462	    /// - `i` must be an index into `val` that points to a '$' char
463	    ///
464	    /// npm/ini uses a regex pattern that will select the inner most ${...}
465	    /// Supports ${VAR} and ${VAR?} syntax:
466	    /// - ${VAR} - if undefined, returns null (leaves as-is)
467	    /// - ${VAR?} - if undefined, expands to empty string
468	    fn parseEnvSubstitution(this: *Parser, val: []const u8, start: usize, i: usize, unesc: *std.array_list.Managed(u8)) OOM!?usize {
469	        bun.debugAssert(val[i] == '$');
470	        var esc = false;
471	        if (i + "{}".len < val.len and val[i + 1] == '{') {
