        const key = bun.String.createUTF8(part);
        defer key.deref();

        const existing = try current.getWithString(global, key);
        if (existing != .undefined and existing != .zero and !existing.isEmptyOrUndefinedOrNull()) {
            current = existing;
        } else {
            const new_obj = JSValue.createEmptyObjectWithNullPrototype(global);
            try current.putMayBeIndex(global, &key, new_obj);
            current = new_obj;
        }
    }

    return current;
}

/// Coerce an INI value string to an appropriate JS value.
fn coerceValue(global: *jsc.JSGlobalObject, raw: []const u8) jsc.JSValue {
    if (raw.len == 0) return jsc.JSValue.jsEmptyString(global);

    // Handle quoted strings (single or double quotes)
    if (raw.len >= 2) {
        if ((raw[0] == '"' and raw[raw.len - 1] == '"') or
            (raw[0] == '\'' and raw[raw.len - 1] == '\''))
        {
            const inner = raw[1 .. raw.len - 1];
            var str = bun.String.createUTF8(inner);
            defer str.deref();
            return str.toJS(global);
        }
    }

    // Strip inline comments (after space+; or space+#)
    const val = stripInlineComment(raw);
    if (val.len == 0) return jsc.JSValue.jsEmptyString(global);

    // Boolean true
    if (bun.strings.eqlCaseInsensitiveASCII(val, "true", true) or
        bun.strings.eqlCaseInsensitiveASCII(val, "yes", true) or
        bun.strings.eqlCaseInsensitiveASCII(val, "on", true))
    {
        return .jsBoolean(true);
    }

    // Boolean false
    if (bun.strings.eqlCaseInsensitiveASCII(val, "false", true) or
        bun.strings.eqlCaseInsensitiveASCII(val, "no", true) or
        bun.strings.eqlCaseInsensitiveASCII(val, "off", true) or
        bun.strings.eqlCaseInsensitiveASCII(val, "none", true))
    {
        return .jsBoolean(false);
    }

    // Null
    if (bun.strings.eqlCaseInsensitiveASCII(val, "null", true)) {
        return .null;
    }

    // Try integer
    if (parseInt(val)) |int_val| {
        return .jsNumber(int_val);
    }

    // Try float
    if (parseFloat(val)) |float_val| {
        return .jsNumber(float_val);
    }

    // String value
    var str = bun.String.createUTF8(val);
    defer str.deref();
    return str.toJS(global);
}

fn parseInt(val: []const u8) ?f64 {
    if (val.len == 0) return null;
    var i: usize = 0;
    var negative = false;
    if (val[0] == '-' or val[0] == '+') {
        negative = val[0] == '-';
        i = 1;
    }
    if (i >= val.len) return null;
    // Must start with a digit
    if (val[i] < '0' or val[i] > '9') return null;
    var result: i64 = 0;
    while (i < val.len) : (i += 1) {
        const c = val[i];
        if (c < '0' or c > '9') return null;
        result = std.math.mul(i64, result, 10) catch return null;
        result = std.math.add(i64, result, @as(i64, c - '0')) catch return null;
    }
    if (negative) result = -result;
    return @as(f64, @floatFromInt(result));
}

fn parseFloat(val: []const u8) ?f64 {
    if (val.len == 0) return null;
    var has_dot = false;
    var i: usize = 0;
    if (val[0] == '-' or val[0] == '+') i = 1;
    if (i >= val.len) return null;
    // Must start with a digit or dot
    if ((val[i] < '0' or val[i] > '9') and val[i] != '.') return null;
    while (i < val.len) : (i += 1) {
        const c = val[i];
        if (c == '.') {
            if (has_dot) return null;
            has_dot = true;
        } else if (c == 'e' or c == 'E') {
            // Exponential notation
            i += 1;
            if (i < val.len and (val[i] == '+' or val[i] == '-')) i += 1;
            if (i >= val.len) return null;
            while (i < val.len) : (i += 1) {
                if (val[i] < '0' or val[i] > '9') return null;
            }
            break;
        } else if (c < '0' or c > '9') {
            return null;
        }
    }
    if (!has_dot) return null; // parseInt would have caught it
    return std.fmt.parseFloat(f64, val) catch null;
}

fn stripInlineComment(val: []const u8) []const u8 {
    // Look for ' ;' or ' #' pattern (space followed by comment char)
    var i: usize = 1;
    while (i < val.len) : (i += 1) {
        if (val[i - 1] == ' ' and (val[i] == ';' or val[i] == '#')) {
            return trim(val[0 .. i - 1]);
        }
    }
    return val;
}

fn findLineEnd(input: []const u8, start: usize) usize {
    var i = start;
    while (i < input.len) : (i += 1) {
        if (input[i] == '\n' or input[i] == '\r') return i;
    }
    return i;
}

fn skipNewline(input: []const u8, pos: usize) usize {
    if (pos >= input.len) return pos;
    if (input[pos] == '\r') {
        if (pos + 1 < input.len and input[pos + 1] == '\n') return pos + 2;
        return pos + 1;
    }
    if (input[pos] == '\n') return pos + 1;
    return pos;
}

fn trim(s: []const u8) []const u8 {
    var start: usize = 0;
    while (start < s.len and isSpace(s[start])) : (start += 1) {}
    var end: usize = s.len;
    while (end > start and isSpace(s[end - 1])) : (end -= 1) {}
    return s[start..end];
}

fn isSpace(c: u8) bool {
    return c == ' ' or c == '\t' or c == '\r' or c == '\n';
}

// ── Stringifier ──────────────────────────────────────────────

const Stringifier = struct {
    builder: wtf.StringBuilder,

    pub fn init() Stringifier {
        return .{
            .builder = .init(),
        };
    }

    pub fn deinit(this: *Stringifier) void {
        this.builder.deinit();
    }

    pub fn stringifyTopLevel(this: *Stringifier, global: *jsc.JSGlobalObject, value: jsc.JSValue) bun.JSError!void {
        if (!value.isObject()) {
            return global.throw("INI.stringify expects an object", .{});
        }

        const obj = try value.toObject(global);

        // First pass: write top-level non-object properties
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(global, obj);
        defer iter.deinit();

        while (try iter.next()) |prop_name| {
            const prop_value = iter.value;
            if (prop_value.isUndefined() or prop_value.isSymbol() or prop_value.isFunction()) {
                continue;
            }

            // Skip objects (they become sections)
            if (prop_value.isObject() and !prop_value.isNull()) {
                continue;
            }

            this.appendKey(prop_name);
            this.builder.append(.latin1, "=");
            try this.appendValue(global, prop_value);
            this.builder.append(.lchar, '\n');
        }

        // Second pass: write sections for object properties
        var iter2: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(global, obj);
        defer iter2.deinit();

        var has_top_level = iter.len > 0;
        _ = &has_top_level;

        while (try iter2.next()) |prop_name| {
            const prop_value = iter2.value;
            if (prop_value.isUndefined() or prop_value.isSymbol() or prop_value.isFunction()) {
                continue;
            }

            if (!prop_value.isObject() or prop_value.isNull()) {
                continue;
            }

            // Write section header
            this.builder.append(.lchar, '\n');
            this.builder.append(.lchar, '[');
            this.appendKey(prop_name);
            this.builder.append(.latin1, "]\n");

            try this.stringifySection(global, prop_value, prop_name);
        }
    }

    fn stringifySection(this: *Stringifier, global: *jsc.JSGlobalObject, value: jsc.JSValue, section_prefix: bun.String) bun.JSError!void {
        const obj = try value.toObject(global);

        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(global, obj);
        defer iter.deinit();

        while (try iter.next()) |prop_name| {
            const prop_value = iter.value;
            if (prop_value.isUndefined() or prop_value.isSymbol() or prop_value.isFunction()) {
                continue;
            }

            if (prop_value.isObject() and !prop_value.isNull()) {
                // Nested section: [parent.child]
                this.builder.append(.lchar, '\n');
                this.builder.append(.lchar, '[');
                this.appendKey(section_prefix);
                this.builder.append(.lchar, '.');
                this.appendKey(prop_name);
                this.builder.append(.latin1, "]\n");
                try this.stringifySection(global, prop_value, prop_name);
                continue;
            }

            this.appendKey(prop_name);
            this.builder.append(.latin1, "=");
            try this.appendValue(global, prop_value);
            this.builder.append(.lchar, '\n');
        }
    }

    fn appendKey(this: *Stringifier, name: bun.String) void {
        this.builder.append(.string, name);
    }

    fn appendValue(this: *Stringifier, global: *jsc.JSGlobalObject, value: jsc.JSValue) bun.JSError!void {
        if (value.isNull()) {
            this.builder.append(.latin1, "null");
            return;
        }
        if (value.isBoolean()) {
            this.builder.append(.latin1, if (value.asBoolean()) "true" else "false");
            return;
        }
        if (value.isNumber()) {
            if (value.isInt32()) {
                this.builder.append(.int, value.asInt32());
            } else {
                this.builder.append(.double, value.asNumber());
            }
            return;
        }
        if (value.isString()) {
            const str = try value.toBunString(global);
            defer str.deref();
            this.builder.append(.string, str);
            return;
        }
        // Fallback: convert to string
        const str = try value.toBunString(global);
        defer str.deref();
        this.builder.append(.string, str);
    }
};

