        global: 1,
        a: { foo: "hello" },
        b: { bar: "world" },
      });
    });

    test("dotted section names create nested objects", () => {
      const result = INI.parse("[a.b]\nkey=value\n");
      expect(result).toEqual({ a: { b: { key: "value" } } });
    });

    test("semicolon comments are ignored", () => {
      const result = INI.parse("; this is a comment\nkey=value\n");
      expect(result).toEqual({ key: "value" });
    });

    test("hash comments are ignored", () => {
      const result = INI.parse("# this is a comment\nkey=value\n");
      expect(result).toEqual({ key: "value" });
    });

    test("empty lines are ignored", () => {
      const result = INI.parse("\n\nkey=value\n\n\n");
      expect(result).toEqual({ key: "value" });
    });

    test("boolean coercion", () => {
      const result = INI.parse(
        "a=true\nb=false\nc=yes\nd=no\ne=on\nf=off\ng=none\n",
      );
      expect(result).toEqual({
        a: true,
        b: false,
        c: true,
        d: false,
        e: true,
        f: false,
        g: false,
      });
    });

    test("boolean coercion is case-insensitive", () => {
      const result = INI.parse("a=TRUE\nb=False\nc=YES\nd=No\n");
      expect(result).toEqual({ a: true, b: false, c: true, d: false });
    });

    test("null coercion", () => {
      const result = INI.parse("key=null\n");
      expect(result).toEqual({ key: null });
    });

    test("integer values", () => {
      const result = INI.parse("a=42\nb=-7\nc=0\n");
      expect(result).toEqual({ a: 42, b: -7, c: 0 });
    });

    test("float values", () => {
      const result = INI.parse("a=3.14\nb=-0.5\n");
      expect(result).toEqual({ a: 3.14, b: -0.5 });
    });

    test("double-quoted values stay as strings", () => {
      const result = INI.parse('key="true"\nnum="42"\n');
      expect(result).toEqual({ key: "true", num: "42" });
    });

    test("single-quoted values stay as strings", () => {
      const result = INI.parse("key='hello world'\n");
      expect(result).toEqual({ key: "hello world" });
    });

    test("inline comments with semicolon", () => {
      const result = INI.parse("key=value ; this is a comment\n");
      expect(result).toEqual({ key: "value" });
    });

    test("inline comments with hash", () => {
      const result = INI.parse("key=value # this is a comment\n");
      expect(result).toEqual({ key: "value" });
    });

    test("key without value treated as true", () => {
      const result = INI.parse("flag\n");
      expect(result).toEqual({ flag: true });
    });

    test("empty value is empty string", () => {
      const result = INI.parse("key=\n");
      expect(result).toEqual({ key: "" });
    });

    test("whitespace around keys and values is trimmed", () => {
      const result = INI.parse("  key  =  value  \n");
      expect(result).toEqual({ key: "value" });
    });

    test("whitespace around section names is trimmed", () => {
      const result = INI.parse("[  section  ]\nkey=value\n");
      expect(result).toEqual({ section: { key: "value" } });
    });

    test("handles CRLF line endings", () => {
      const result = INI.parse("key=value\r\nfoo=bar\r\n");
      expect(result).toEqual({ key: "value", foo: "bar" });
    });

    test("handles CR-only line endings", () => {
      const result = INI.parse("key=value\rfoo=bar\r");
      expect(result).toEqual({ key: "value", foo: "bar" });
    });

    test("complex example", () => {
      const input = `
; Database configuration
[database]
host=localhost
port=5432
name=mydb
ssl=true

# Application settings
[app]
debug=false
workers=4
version=1.2.3
`;
      const result = INI.parse(input);
      expect(result).toEqual({
        database: {
          host: "localhost",
          port: 5432,
          name: "mydb",
          ssl: true,
        },
        app: {
          debug: false,
          workers: 4,
          version: "1.2.3",
        },
      });
    });

    test("throws on non-string input", () => {
      // @ts-expect-error
      expect(() => INI.parse()).toThrow();
      // @ts-expect-error
      expect(() => INI.parse(undefined)).toThrow();
      // @ts-expect-error
      expect(() => INI.parse(null)).toThrow();
    });

    test("empty string returns empty object", () => {
      const result = INI.parse("");
      expect(result).toEqual({});
    });

    test("available as named import", () => {
      expect(INI.parse).toBe(Bun.INI.parse);
    });
  });

  describe("stringify", () => {
    test("simple key-value pairs", () => {
      const result = INI.stringify({ key: "value", foo: "bar" });
      expect(result).toContain("key=value");
      expect(result).toContain("foo=bar");
    });

    test("boolean values", () => {
      const result = INI.stringify({ enabled: true, debug: false });
      expect(result).toContain("enabled=true");
      expect(result).toContain("debug=false");
    });

    test("number values", () => {
      const result = INI.stringify({ port: 8080, ratio: 3.14 });
      expect(result).toContain("port=8080");
      expect(result).toContain("ratio=3.14");
    });

    test("null values", () => {
      const result = INI.stringify({ key: null });
      expect(result).toContain("key=null");
    });

    test("sections from nested objects", () => {
      const result = INI.stringify({
        section: { key: "value" },
      });
      expect(result).toContain("[section]");
      expect(result).toContain("key=value");
    });

    test("top-level values come before sections", () => {
      const result = INI.stringify({
        global: "yes",
        section: { key: "value" },
      });
      const globalPos = result.indexOf("global=yes");
      const sectionPos = result.indexOf("[section]");
      expect(globalPos).toBeLessThan(sectionPos);
    });

    test("roundtrip simple object", () => {
      const original = { key: "hello", num: 42, flag: true };
      const roundtripped = INI.parse(INI.stringify(original));
      expect(roundtripped).toEqual(original);
    });

    test("roundtrip with sections", () => {
      const original = {
        database: { host: "localhost", port: 5432 },
      };
      const roundtripped = INI.parse(INI.stringify(original));
      expect(roundtripped).toEqual(original);
    });

    test("throws on non-object input", () => {
      // @ts-expect-error
      expect(() => INI.stringify("hello")).toThrow();
      // @ts-expect-error
      expect(() => INI.stringify(42)).toThrow();
    });

    test("returns undefined for undefined input", () => {
      // @ts-expect-error
      expect(INI.stringify(undefined)).toBeUndefined();
    });

    test("available as named import", () => {
      expect(INI.stringify).toBe(Bun.INI.stringify);
    });
  });
});

