52	/// Self-contained INI parser. Handles sections, key=value pairs, and comment lines (; and #).
53	fn parseINI(global: *jsc.JSGlobalObject, input: []const u8) bun.JSError!jsc.JSValue {
54	    const root = JSValue.createEmptyObjectWithNullPrototype(global);
55	    var current_section = root;
56	
57	    var pos: usize = 0;
58	    while (pos < input.len) {
59	        // Find end of line
60	        const line_end = findLineEnd(input, pos);
61	        const raw_line = input[pos..line_end];
62	        pos = skipNewline(input, line_end);
63	
64	        // Trim whitespace
65	        const line = trim(raw_line);
66	
67	        // Skip empty lines and comments
68	        if (line.len == 0) continue;
69	        if (line[0] == ';' or line[0] == '#') continue;
70	
71	        // Section header
72	        if (line[0] == '[') {
73	            if (std.mem.indexOfScalar(u8, line, ']')) |close| {
74	                const section_name = trim(line[1..close]);
75	                if (section_name.len > 0) {
76	                    // Create nested section (supports dotted names like [a.b])
77	                    current_section = try getOrCreateSection(global, root, section_name);
78	                    continue;
79	                }
80	            }
81	            // Malformed section header - skip
82	            continue;
83	        }
84	
85	        // Key=value pair
86	        if (std.mem.indexOfScalar(u8, line, '=')) |eq_pos| {
87	            const raw_key = trim(line[0..eq_pos]);
88	            const raw_val = trim(line[eq_pos + 1 ..]);
89	
90	            if (raw_key.len > 0) {
91	                const key_str = bun.String.cloneUTF8(raw_key);
92	                defer key_str.deref();
93	                const val = try coerceValue(global, raw_val);
94	                try current_section.putMayBeIndex(global, &key_str, val);
95	            }
96	        } else {
97	            // Key without value - treat as true
98	            const raw_key = trim(line);
99	            if (raw_key.len > 0) {
100	                const key_str = bun.String.cloneUTF8(raw_key);
101	                defer key_str.deref();
102	                try current_section.putMayBeIndex(global, &key_str, .jsBoolean(true));
103	            }
104	        }
105	    }
106	
107	    return root;
