110	fn getOrCreateSection(global: *jsc.JSGlobalObject, root: jsc.JSValue, name: []const u8) bun.JSError!jsc.JSValue {
111	    var current = root;
112	    var rest = name;
113	
114	    while (rest.len > 0) {
115	        const dot_pos = std.mem.indexOfScalar(u8, rest, '.') orelse rest.len;
116	        const part = rest[0..dot_pos];
117	        rest = if (dot_pos < rest.len) rest[dot_pos + 1 ..] else &.{};
118	
119	        if (part.len == 0) continue;
120	
121	        const existing = try current.getPropertyValue(global, part);
122	        if (existing) |val| {
123	            if (val.isObject()) {
124	                current = val;
125	                continue;
126	            }
127	        }
128	        // Create new section object
129	        const key = bun.String.cloneUTF8(part);
130	        defer key.deref();
131	        const new_obj = JSValue.createEmptyObjectWithNullPrototype(global);
132	        try current.putMayBeIndex(global, &key, new_obj);
133	        current = new_obj;
134	    }
135	
136	    return current;
137	}
