140	fn coerceValue(global: *jsc.JSGlobalObject, raw: []const u8) bun.JSError!jsc.JSValue {
141	    if (raw.len == 0) return jsc.JSValue.jsEmptyString(global);
142	
143	    // Handle quoted strings (single or double quotes)
144	    if (raw.len >= 2) {
145	        if ((raw[0] == '"' and raw[raw.len - 1] == '"') or
146	            (raw[0] == '\'' and raw[raw.len - 1] == '\''))
147	        {
148	            const inner = raw[1 .. raw.len - 1];
149	            var str = bun.String.cloneUTF8(inner);
150	            defer str.deref();
151	            return try str.toJS(global);
152	        }
153	    }
154	
155	    // Strip inline comments (after space+; or space+#)
156	    const val = stripInlineComment(raw);
157	    if (val.len == 0) return jsc.JSValue.jsEmptyString(global);
158	
159	    // Boolean true
160	    if (bun.strings.eqlCaseInsensitiveASCII(val, "true", true) or
161	        bun.strings.eqlCaseInsensitiveASCII(val, "yes", true) or
162	        bun.strings.eqlCaseInsensitiveASCII(val, "on", true))
163	    {
164	        return .jsBoolean(true);
165	    }
166	
167	    // Boolean false
168	    if (bun.strings.eqlCaseInsensitiveASCII(val, "false", true) or
169	        bun.strings.eqlCaseInsensitiveASCII(val, "no", true) or
170	        bun.strings.eqlCaseInsensitiveASCII(val, "off", true) or
171	        bun.strings.eqlCaseInsensitiveASCII(val, "none", true))
172	    {
173	        return .jsBoolean(false);
174	    }
175	
176	    // Null
177	    if (bun.strings.eqlCaseInsensitiveASCII(val, "null", true)) {
178	        return .null;
179	    }
180	
181	    // Try integer
182	    if (parseInt(val)) |int_val| {
183	        return .jsNumber(int_val);
184	    }
185	
186	    // Try float
187	    if (parseFloat(val)) |float_val| {
188	        return .jsNumber(float_val);
189	    }
190	
191	    // String value
192	    var str = bun.String.cloneUTF8(val);
193	    defer str.deref();
194	    return try str.toJS(global);
195	}
