197	fn parseInt(val: []const u8) ?f64 {
198	    if (val.len == 0) return null;
199	    var i: usize = 0;
200	    var negative = false;
201	    if (val[0] == '-' or val[0] == '+') {
202	        negative = val[0] == '-';
203	        i = 1;
204	    }
205	    if (i >= val.len) return null;
206	    // Must start with a digit
207	    if (val[i] < '0' or val[i] > '9') return null;
208	    var result: i64 = 0;
209	    while (i < val.len) : (i += 1) {
210	        const c = val[i];
211	        if (c < '0' or c > '9') return null;
212	        result = std.math.mul(i64, result, 10) catch return null;
213	        result = std.math.add(i64, result, @as(i64, c - '0')) catch return null;
214	    }
215	    if (negative) result = -result;
216	    return @as(f64, @floatFromInt(result));
217	}
