219	fn parseFloat(val: []const u8) ?f64 {
220	    if (val.len == 0) return null;
221	    var has_dot = false;
222	    var i: usize = 0;
223	    if (val[0] == '-' or val[0] == '+') i = 1;
224	    if (i >= val.len) return null;
225	    // Must start with a digit or dot
226	    if ((val[i] < '0' or val[i] > '9') and val[i] != '.') return null;
227	    while (i < val.len) : (i += 1) {
228	        const c = val[i];
229	        if (c == '.') {
230	            if (has_dot) return null;
231	            has_dot = true;
232	        } else if (c == 'e' or c == 'E') {
233	            // Exponential notation
234	            i += 1;
235	            if (i < val.len and (val[i] == '+' or val[i] == '-')) i += 1;
236	            if (i >= val.len) return null;
237	            while (i < val.len) : (i += 1) {
238	                if (val[i] < '0' or val[i] > '9') return null;
239	            }
240	            break;
241	        } else if (c < '0' or c > '9') {
242	            return null;
243	        }
244	    }
245	    if (!has_dot) return null; // parseInt would have caught it
246	    return std.fmt.parseFloat(f64, val) catch null;
247	}
