278	fn trim(s: []const u8) []const u8 {
279	    var start: usize = 0;
280	    while (start < s.len and isSpace(s[start])) : (start += 1) {}
281	    var end: usize = s.len;
282	    while (end > start and isSpace(s[end - 1])) : (end -= 1) {}
283	    return s[start..end];
