pub fn stringify(
    global: *jsc.JSGlobalObject,
    callFrame: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const value = callFrame.argument(0);

    value.ensureStillAlive();

    if (value.isUndefined() or value.isSymbol() or value.isFunction()) {
        return .js_undefined;
    }

    var stringifier: Stringifier = .init();
    defer stringifier.deinit();

    try stringifier.stringifyTopLevel(global, value);

    return stringifier.builder.toString(global);
}

/// Self-contained INI parser. Handles sections, key=value pairs, and comment lines (; and #).
fn parseINI(global: *jsc.JSGlobalObject, input: []const u8) bun.JSError!jsc.JSValue {
    const root = JSValue.createEmptyObjectWithNullPrototype(global);
    var current_section = root;

    var pos: usize = 0;
    while (pos < input.len) {
        // Find end of line
        const line_end = findLineEnd(input, pos);
        const raw_line = input[pos..line_end];
        pos = skipNewline(input, line_end);

        // Trim whitespace
        const line = trim(raw_line);

        // Skip empty lines and comments
        if (line.len == 0) continue;
        if (line[0] == ';' or line[0] == '#') continue;

        // Section header
        if (line[0] == '[') {
            if (std.mem.indexOfScalar(u8, line, ']')) |close| {
                const section_name = trim(line[1..close]);
                if (section_name.len > 0) {
                    // Create nested section (supports dotted names like [a.b])
                    current_section = try getOrCreateSection(global, root, section_name);
                    continue;
                }
            }
            // Malformed section header - skip
            continue;
        }

        // Key=value pair
        if (std.mem.indexOfScalar(u8, line, '=')) |eq_pos| {
            const raw_key = trim(line[0..eq_pos]);
            const raw_val = trim(line[eq_pos + 1 ..]);

            if (raw_key.len > 0) {
                const key_str = bun.String.cloneUTF8(raw_key);
                defer key_str.deref();
                const val = try coerceValue(global, raw_val);
                try current_section.putMayBeIndex(global, &key_str, val);
            }
        } else {
            // Key without value - treat as true
            const raw_key = trim(line);
            if (raw_key.len > 0) {
                const key_str = bun.String.cloneUTF8(raw_key);
                defer key_str.deref();
                try current_section.putMayBeIndex(global, &key_str, .jsBoolean(true));
            }
        }
    }

    return root;
}

